// Minimal OpenTelemetry + Express example (Node.js)
// Install: npm i @opentelemetry/sdk-node @opentelemetry/auto-instrumentations-node @opentelemetry/exporter-jaeger express axios

// otel-bootstrap.js
const { NodeSDK } = require('@opentelemetry/sdk-node');
const { getNodeAutoInstrumentations } = require('@opentelemetry/auto-instrumentations-node');
const { JaegerExporter } = require('@opentelemetry/exporter-jaeger');

const sdk = new NodeSDK({
  traceExporter: new JaegerExporter({ endpoint: 'http://localhost:14268/api/traces' }),
  instrumentations: [getNodeAutoInstrumentations()]
});

sdk.start().then(() => {
  require('./app'); // your Express app will now auto-instrument
});

// app.js
const express = require('express');
const axios = require('axios');
const app = express();
app.get('/checkout', async (req, res) => {
  const [cart, price] = await Promise.all([
    axios.get('http://localhost:4000/cart'),
    axios.get('http://localhost:5000/price')
  ]);
  res.json({ cart: cart.data, price: price.data });
});
app.listen(3000, () => console.log('Listening'));
